struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet;

    // Read packet_id
    stream >> packet.packet_id;

    // Read username using length prefix
    stream.prefixed() >> packet.username;

    // Read score count, then use read_container to read the scores vector
    stream.read_container(packet.scores);

    // Read metadata as null-terminated string for zero-copy
    stream.null_terminated() >> packet.metadata;

    // Any remaining padding bytes are automatically handled by stream end

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
