    auto id_span = stream.span<uint32_t>(1);
    info.packet_id = id_span[0];

    // Read username using prefixed adaptor to get a string_view
    stream.prefixed() >> info.username;

    // Skip the scores vector without reading its elements
    // Read count, then skip the data
    uint32_t scores_count;
    stream >> scores_count;
    stream.skip(scores_count * sizeof(uint32_t));

    return info;
}
