// Helper function to create message buffer
std::vector<uint8_t> create_message_buffer(const std::string& message) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << hexi::null_terminated(message);
    return buffer;
}

