#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

std::vector<uint32_t> read_item_batch(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    std::vector<uint32_t> items;
    stream >> hexi::prefixed(items);

    return items;
}

