std::vector<uint8_t> create_batch_buffer(const std::vector<uint32_t>& items) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << hexi::prefixed(items);

    return buffer;
}

TEST(ItemBatch, ReadBatch) {
    std::vector<uint32_t> expected = {10, 20, 30, 40, 50};
    auto buffer = create_batch_buffer(expected);

    std::vector<uint32_t> items = read_item_batch(buffer);

    EXPECT_EQ(expected, items);
}

TEST(ItemBatch, ReadLargeBatch) {
    std::vector<uint32_t> expected(1000, 42);
    auto buffer = create_batch_buffer(expected);

    std::vector<uint32_t> items = read_item_batch(buffer);

    EXPECT_EQ(expected.size(), items.size());
    EXPECT_EQ(expected, items);
}

