}

TEST(BufferAdaptor, ReadWriteRoundTrip) {
    std::vector<uint8_t> original = {100, 200, 150, 250};
    std::vector<uint8_t> buffer;

    write_buffer_data(buffer, original);
    auto read_back = read_buffer_data(buffer, original.size());

    EXPECT_EQ(original, read_back);
}

