#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    return reinterpret_cast<const uint8_t*>(adaptor.data());
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    return reinterpret_cast<uint8_t*>(adaptor.data() + adaptor.size());
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    BufferInfo info;
    info.readable_size = adaptor.size();
    info.free_space = adaptor.capacity() - adaptor.size();
    return info;
}
```

## Explanation:

1. **`get_read_pointer`**: Creates a `hexi::buffer_adaptor` from the const buffer and returns a pointer to the beginning of the readable data using `adaptor.data()`. The pointer is cast from `std::byte*` to `uint8_t*`.

2. **`get_write_pointer`**: Creates a `hexi::buffer_adaptor` from the buffer and returns a pointer to the current write position, which is at `data() + size()` (end of the currently written data).

3. **`check_buffer_space`**: Creates a `hexi::buffer_adaptor` and retrieves:
   - `readable_size`: The amount of data available to read (`size()`)
   - `free_space`: The available space for writing (`capacity() - size()`)

The `hexi::buffer_adaptor` provides a convenient interface for managing buffer pointers and tracking read/write positions within the underlying container.

