```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor to manage the buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with no_throw to handle errors gracefully
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Calculate required space: header + container size prefix + items data
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + items.size() * sizeof(uint32_t);

    // Check available space in buffer
    if (buffer.capacity() - buffer.size() < required_space) {
        // Attempt to reserve space; if this fails (e.g., memory allocation), return false
        try {
            buffer.reserve(buffer.size() + required_space);
        } catch (...) {
            return false;
        }
    }

    // Write header value
    stream.put(header);

    // Write container data (vector of items)
    stream.write_container(items);

    // Return true if write was successful, false if stream is in error state
    return static_cast<bool>(stream);
}
```

