    size_t available = buffer.size();
    size_t actual_peek = std::min(bytes_to_peek, available);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result(actual_peek);

    // Copy data without advancing read pointer
    if (actual_peek > 0) {
        buffer.copy(result.data(), actual_peek);
    }

    return result;
}

