template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    if (from == to) {
        return value;
    }

    // Need to swap bytes when from != to
    if constexpr(std::is_same_v<T, float>) {
        return std::bit_cast<T>(std::byteswap(std::bit_cast<std::uint32_t>(value)));
    } else if constexpr(std::is_same_v<T, double>) {
        return std::bit_cast<T>(std::byteswap(std::bit_cast<std::uint64_t>(value)));
    } else {
        return std::byteswap(value);
    }
}

