// Include the implementation
#include "implementation.hpp"

TEST(StaticBuffer, ReadWriteUint32) {
    hexi::static_buffer<std::byte, 1024> buffer;
    uint32_t original_value = 12345678;

    write_uint32_to_buffer(buffer, original_value);
    uint32_t read_value = read_uint32_from_buffer(buffer);

    EXPECT_EQ(original_value, read_value);
}

TEST(StaticBuffer, ReadWriteMultipleUint32) {
    hexi::static_buffer<std::byte, 1024> buffer;
    uint32_t values[] = {0, 1, 4294967295, 42, 999999};

    for (auto value : values) {
        write_uint32_to_buffer(buffer, value);
    }

    for (auto expected_value : values) {
        uint32_t read_value = read_uint32_from_buffer(buffer);
        EXPECT_EQ(expected_value, read_value);
    }
}

TEST(StaticBuffer, ReadWriteUint32RoundTrip) {
    hexi::static_buffer<std::byte, 1024> buffer;
    uint32_t test_values[] = {100, 200, 300};

    for (auto value : test_values) {
        write_uint32_to_buffer(buffer, value);
    }

    for (auto expected_value : test_values) {
        uint32_t read_value = read_uint32_from_buffer(buffer);
        EXPECT_EQ(expected_value, read_value);
    }
}

