```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned type to handle bit operations correctly
    using UnsignedT = std::make_unsigned_t<T>;
    UnsignedT uvalue = static_cast<UnsignedT>(value);

    // Encode 7 bits at a time, setting the MSB if more bytes follow
    while (uvalue > 0x7F) {
        std::uint8_t byte = (uvalue & 0x7F) | 0x80;  // Set continuation bit
        writer << byte;
        uvalue >>= 7;
        bytes_written++;
    }

    // Write the final byte (no continuation bit)
    std::uint8_t byte = uvalue & 0x7F;
    writer << byte;
    bytes_written++;

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    while (true) {
        std::uint8_t byte;
        reader >> byte;

        // Extract the 7 data bits and add to result
        result |= static_cast<T>(byte & 0x7F) << shift;

        // Check if this is the last byte (MSB not set)
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    std::vector<std::uint8_t> buffer;

    // Encode the value
    {
        hexi::pmc::buffer_adaptor write_adaptor(buffer);
        hexi::pmc::binary_stream_writer writer(write_adaptor);
        encode_varint(writer, original_value);
    }

    // Decode the value
    T decoded_value;
    {
        hexi::pmc::buffer_adaptor read_adaptor(buffer);
        hexi::pmc::binary_stream_reader reader(read_adaptor);
        decoded_value = decode_varint<T>(reader);
    }

    // Verify roundtrip correctness
    return decoded_value == original_value;
}
```

